SQL:
SELECT CadastroAcolhidos.NomeAcolhido, CadastroAcolhidos.NDestituicao, CadastroAcolhidos.DataDesacolhimento, CadastroAcolhidos.NPedProv, CadastroAcolhidos.EntidadeAcolhimento, CadastroAcolhidos.DataAcolhimento, fncPeriodoAcolhimento(Nz([DataAcolhimento],0)) AS [Periodo Acolhimento]
FROM CadastroAcolhidos
WHERE (((CadastroAcolhidos.NDestituicao) Is Null) AND ((CadastroAcolhidos.DataDesacolhimento) Is Null));

SELECT CadastroAcolhidos.NomeAcolhido, CadastroAcolhidos.EntidadeAcolhimento, CadastroAcolhidos.DataDesacolhimento, CadastroAcolhidos.DataInicioDest, CadastroAcolhidos.DataDestituição, CadastroAcolhidos.NDestituicao
FROM CadastroAcolhidos
WHERE (((CadastroAcolhidos.DataDesacolhimento) Is Null) AND ((CadastroAcolhidos.DataDestituição) Is Null) AND ((CadastroAcolhidos.NDestituicao) Is Not Null And (CadastroAcolhidos.NDestituicao)<>""));

SELECT CadastroAcolhidos.NomeAcolhido, CadastroAcolhidos.MaeAcolhido, CadastroAcolhidos.PaiAcolhido, CadastroAcolhidos.EntidadeAcolhimento, CadastroAcolhidos.PeriodoAcolhimento, CadastroAcolhidos.NDestituicao, CadastroAcolhidos.DataDestituição, CadastroAcolhidos.DataTransito, CadastroAcolhidos.AcolhidoDestituido, CadastroAcolhidos.DataDesacolhimento
FROM CadastroAcolhidos
WHERE (((CadastroAcolhidos.AcolhidoDestituido)="sim") AND ((CadastroAcolhidos.DataDesacolhimento) Is Null));

SELECT [Consulta Destituidos].NomeAcolhido, [Consulta Destituidos].NomeAcolhido, [Consulta Destituidos].PaiAcolhido, [Consulta Destituidos].EntidadeAcolhimento, [Consulta Destituidos].PeriodoAcolhimento, [Consulta Destituidos].NDestituicao, [Consulta Destituidos].DataTransito, [Consulta Destituidos].AcolhidoDestituido, [Consulta Destituidos].DataDesacolhimento
FROM [Consulta Destituidos]
WHERE ((([Consulta Destituidos].DataTransito) Is Not Null) AND (([Consulta Destituidos].AcolhidoDestituido)="sim") AND (([Consulta Destituidos].DataDesacolhimento) Is Null));

SELECT CadastroAcolhidos.NomeAcolhido, CadastroAcolhidos.PARESCON, CadastroAcolhidos.NPedProv, CadastroAcolhidos.EntidadeAcolhimento
FROM CadastroAcolhidos
WHERE (((CadastroAcolhidos.PARESCON)="SIM") AND ((CadastroAcolhidos.DataDesacolhimento) Is Null));

SELECT CadastroAcolhidos.NomeAcolhido, CadastroAcolhidos.EntidadeAcolhimento, CadastroAcolhidos.MaeAcolhido, CadastroAcolhidos.NPedProv, CadastroAcolhidos.NDestituicao, fncPeriodoAcolhimento(Nz([DataAcolhimento],0)) AS [Periodo Acolhimento], CadastroAcolhidos.DECVisitas, CadastroAcolhidos.AUTORIZAVisitas, CadastroAcolhidos.DataDesacolhimento
FROM CadastroAcolhidos
WHERE (((CadastroAcolhidos.DECVisitas)="SIM") AND ((CadastroAcolhidos.AUTORIZAVisitas)="NÃO") AND ((CadastroAcolhidos.DataDesacolhimento) Is Null));

SELECT CadastroAcolhidos.NomeAcolhido, CadastroAcolhidos.EntidadeAcolhimento, CadastroAcolhidos.MaeAcolhido, CadastroAcolhidos.NPedProv, CadastroAcolhidos.NDestituicao, fncPeriodoAcolhimento(Nz([DataAcolhimento],0)) AS [Periodo Acolhimento], CadastroAcolhidos.DECVisitas, CadastroAcolhidos.DataAcolhimento, CadastroAcolhidos.DataDesacolhimento
FROM CadastroAcolhidos
WHERE (((CadastroAcolhidos.DECVisitas)="NÃO") AND ((CadastroAcolhidos.DataAcolhimento)<Date()-15) AND ((CadastroAcolhidos.DataDesacolhimento) Is Null));

SELECT ConsultaTodosAcolhidosEntidade.NomeAcolhido, ConsultaTodosAcolhidosEntidade.DataDesacolhimento
FROM ConsultaTodosAcolhidosEntidade
WHERE (((ConsultaTodosAcolhidosEntidade.DataDesacolhimento) Is Null));

SELECT CadastroAcolhidos.NomeAcolhido, CadastroAcolhidos.EntidadeAcolhimento, CadastroAcolhidos.DataDesacolhimento, CadastroAcolhidos.AUTORIZAVisitas, CadastroAcolhidos.DataDecidVisitas, CadastroAcolhidos.DataAcolhimento, CadastroAcolhidos.DataDestituição, CadastroAcolhidos.NDestituicao
FROM CadastroAcolhidos
WHERE (((CadastroAcolhidos.DataDesacolhimento) Is Null) AND ((CadastroAcolhidos.AUTORIZAVisitas)="Não") AND ((CadastroAcolhidos.DataAcolhimento)<Date()-180) AND ((CadastroAcolhidos.NDestituicao) Is Null));

SELECT CadastroAcolhidos.NomeAcolhido, CadastroAcolhidos.EntidadeAcolhimento, CadastroAcolhidos.MaeAcolhido, CadastroAcolhidos.PaiAcolhido, CadastroAcolhidos.DataAcolhimento, CadastroAcolhidos.MotivoAcolhimento, CadastroAcolhidos.DataDesacolhimento, CadastroAcolhidos.MotivoDesacolhimento, CadastroAcolhidos.NPedProv, CadastroAcolhidos.AtualizacaoFicha
FROM CadastroAcolhidos
WHERE (((CadastroAcolhidos.DataDesacolhimento)=[DataDesacolhimento]));

SELECT CadastroAcolhidos.CódigoAcolhido, CadastroAcolhidos.NomeAcolhido, CadastroAcolhidos.MaeAcolhido, CadastroAcolhidos.PaiAcolhido, CadastroAcolhidos.DataNascimentoAcolhido, CadastroAcolhidos.IdadeAcolhido, CadastroAcolhidos.DataAcolhimento, [Entidades de Acolhimento].NomeEntidade, CadastroAcolhidos.PeriodoAcolhimento, CadastroAcolhidos.MotivoAcolhimento, CadastroAcolhidos.NPedProv, CadastroAcolhidos.NDestituicao, CadastroAcolhidos.NGuiaAcolhimento, CadastroAcolhidos.DataDesacolhimento, CadastroAcolhidos.AcolhidoEvadido, CadastroAcolhidos.DataEvasão, CadastroAcolhidos.AcolhidoDestituido, CadastroAcolhidos.DataDestituição, CadastroAcolhidos.DataTransito, CadastroAcolhidos.FaseProcessual, CadastroAcolhidos.ImpulsoProcessual, CadastroAcolhidos.Observações
FROM CadastroAcolhidos INNER JOIN [Entidades de Acolhimento] ON CadastroAcolhidos.EntidadeAcolhimento = [Entidades de Acolhimento].NomeEntidade
WHERE ((([Entidades de Acolhimento].NomeEntidade)="Casa Lar Dorcas") AND ((CadastroAcolhidos.DataDesacolhimento) Is Null));

SELECT fncIdadeCompleta(Nz([DataNascimentoAcolhido],0)) AS [Idade Completa], fncPeriodoAcolhimento(Nz([DataAcolhimento],0)) AS [Periodo Acolhimento], [Ficha Individual].NomeAcolhido, [Ficha Individual].MaeAcolhido, [Ficha Individual].PaiAcolhido, [Ficha Individual].DataNascimentoAcolhido, [Ficha Individual].DataAcolhimento, [Ficha Individual].EntidadeAcolhimento, [Ficha Individual].MotivoAcolhimento, [Ficha Individual].NPedProv, [Ficha Individual].NDestituicao, [Ficha Individual].NGuiaAcolhimento, [Ficha Individual].AcolhidoEvadido, [Ficha Individual].DataEvasão, [Ficha Individual].AcolhidoDestituido, [Ficha Individual].DataTransito, [Ficha Individual].FaseProcessual, [Ficha Individual].Observações, [Ficha Individual].ImpulsoProcessual, [Ficha Individual].DataDestituição, [Ficha Individual].FaseProcessual, [Ficha Individual].AtualizacaoFicha
FROM [Ficha Individual]
WHERE ((([Ficha Individual].NDestituicao) Is Null));

SELECT CadastroAcolhidos.NomeAcolhido, CadastroAcolhidos.EntidadeAcolhimento, CadastroAcolhidos.DataDesacolhimento, CadastroAcolhidos.NDestituicao, CadastroAcolhidos.DataInicioDest, CadastroAcolhidos.DataDestituição
FROM CadastroAcolhidos
WHERE (((CadastroAcolhidos.DataDesacolhimento) Is Null) AND ((CadastroAcolhidos.DataInicioDest)<Date()-120) AND ((CadastroAcolhidos.DataDestituição) Is Null));

SELECT CadastroAcolhidos.CódigoAcolhido, CadastroAcolhidos.NomeAcolhido, CadastroAcolhidos.MaeAcolhido, CadastroAcolhidos.PaiAcolhido, CadastroAcolhidos.DataNascimentoAcolhido, fncIdadeCompleta(Nz([DataNascimentoAcolhido],0)) AS [Idade Completa], CadastroAcolhidos.DataAcolhimento, CadastroAcolhidos.EntidadeAcolhimento, fncPeriodoAcolhimento(Nz([DataAcolhimento],0)) AS [Periodo Acolhimento], CadastroAcolhidos.MotivoAcolhimento, CadastroAcolhidos.NPedProv, CadastroAcolhidos.NDestituicao, CadastroAcolhidos.NGuiaAcolhimento, CadastroAcolhidos.DataDesacolhimento, CadastroAcolhidos.AcolhidoEvadido, CadastroAcolhidos.DataEvasão, CadastroAcolhidos.DataRetorno, CadastroAcolhidos.MotivoDesacolhimento, CadastroAcolhidos.AcolhidoDestituido, CadastroAcolhidos.DataDestituição, CadastroAcolhidos.DataTransito, CadastroAcolhidos.AcolhidoAdotado, CadastroAcolhidos.DadosAdocao, CadastroAcolhidos.FaseProcessual, CadastroAcolhidos.ImpulsoProcessual, CadastroAcolhidos.Observações, CadastroAcolhidos.AtualizacaoFicha
FROM CadastroAcolhidos
WHERE (((CadastroAcolhidos.DataDesacolhimento) Is Null));

SELECT CadastroAcolhidos.NPedProv, CadastroAcolhidos.NDestituicao, CadastroAcolhidos.NomeAcolhido, CadastroAcolhidos.DataAcolhimento, CadastroAcolhidos.EntidadeAcolhimento, CadastroAcolhidos.PARESCON, CadastroAcolhidos.DataDesacolhimento
FROM CadastroAcolhidos
WHERE (((CadastroAcolhidos.NDestituicao) Is Null) AND ((CadastroAcolhidos.PARESCON)="SIM") AND ((CadastroAcolhidos.DataDesacolhimento) Is Null));
